// Validate secret and load content + scene data
const data = $input.first().json;
const expectedSecret = $env.N8N_WEBHOOK_HMAC_SECRET;

if (!expectedSecret) throw new Error('N8N_WEBHOOK_HMAC_SECRET not configured');

const headers = data.headers || {};
const body    = data.body    || data || {};
const receivedSecret = headers['x-webhook-secret'] || body.secret || '';

if (receivedSecret !== expectedSecret) throw new Error('Invalid webhook secret');

const content_id = body.content_id || '';
if (!content_id) throw new Error('Missing required field: content_id');

// Load content metadata
const contentResp = await $http.request({
  method: 'POST',
  url: 'http://localhost:5678/webhook/cf-read-content',
  body: { secret: expectedSecret, action: 'read_content', content_id },
  json: true
});
const content = contentResp.content || {};

// Load scenes
const scenesResp = await $http.request({
  method: 'POST',
  url: 'http://localhost:5678/webhook/cf-scene',
  body: { secret: expectedSecret, action: 'list_scenes', content_id },
  json: true
});
const scenes = scenesResp.scenes || [];

if (scenes.length === 0) throw new Error(`No scenes found for content_id: ${content_id}`);

return [{ json: { content_id, content, scenes, authenticated: true } }];

// Assign providers to each scene based on description keywords
const { content_id, content, scenes } = $input.first().json;

// Map content format to Remotion composition name
const formatMap = {
  'reel-motion-text':       'ReelMotionText',
  'reel-meme-skit':         'ReelMemeSkit',
  'reel-feature-showcase':  'ReelFeatureShowcase',
  'reel-teaser':            'ReelTeaser'
};
const compositionName = formatMap[content.format] || 'ReelMotionText';

// Motion/animation keywords that trigger Remotion over ComfyUI
const motionKeywords = [
  'animation', 'animate', 'motion', 'moving', 'transition', 'effect',
  'zoom', 'pan', 'slide', 'rotate', 'spin', 'bounce', 'fade',
  'dynamic', 'kinetic', 'video', 'loop'
];

const assignedScenes = scenes.map(scene => {
  const desc = (scene.visual_description || scene.description || '').toLowerCase();
  const hasMotion = motionKeywords.some(kw => desc.includes(kw));

  let assigned_model, assigned_type;
  if (hasMotion) {
    // Motion/animation -> Remotion composition
    assigned_model = 'remotion';
    assigned_type  = 'video-composition';
  } else if (scene.provider === 'comfyui' || (!scene.provider && !hasMotion)) {
    // Static image -> local ComfyUI first
    assigned_model = 'comfyui';
    assigned_type  = 'image';
  } else {
    // Default fallback -> cloud Seedream
    assigned_model = 'seedream';
    assigned_type  = 'image';
  }

  return { ...scene, assigned_model, assigned_type, composition: compositionName };
});

return [{ json: { content_id, content, compositionName, assignedScenes } }];

// Sequential dispatch to creative-pipeline (2s delay between scenes)
const { content_id, content, compositionName, assignedScenes } = $input.first().json;
const expectedSecret = $env.N8N_WEBHOOK_HMAC_SECRET;

const brandData = {
  name:         content.brand_name         || '',
  primaryColor: content.brand_palette?.primary || '#FF6B00',
  font:         content.brand_typography    || 'Inter'
};

const results = [];

for (const scene of assignedScenes) {
  const payload = {
    type:        scene.assigned_type,
    prompt:      scene.visual_description || scene.description || '',
    model:       scene.assigned_model,
    output_name: `${content_id}-scene-${scene.scene_number}`,
    agent_id:    'content-factory',
    input_props: { scenes: [scene], brand: brandData }
  };

  // Only include composition for video-composition type
  if (scene.assigned_type === 'video-composition') {
    payload.composition = scene.composition || compositionName;
  }

  let result;
  try {
    result = await $http.request({
      method: 'POST',
      url:    'http://localhost:5678/webhook/creative-pipeline',
      body:   payload,
      json:   true
    });
  } catch (err) {
    result = { status: 'error', error: err.message, scene_number: scene.scene_number };
  }

  results.push({
    scene_number: scene.scene_number,
    assigned_model: scene.assigned_model,
    assigned_type:  scene.assigned_type,
    result_url:     result.result_url || null,
    render_id:      result.render_id  || null,
    provider:       result.provider   || scene.assigned_model,
    status:         result.status     || 'dispatched'
  });

  // 2-second delay between dispatches to avoid overwhelming local services
  if (assignedScenes.indexOf(scene) < assignedScenes.length - 1) {
    await new Promise(r => setTimeout(r, 2000));
  }
}

return [{ json: { content_id, content, results, scenes_dispatched: results.length } }];

// Update scene status in NocoDB for each dispatched scene
const { content_id, content, results, scenes_dispatched } = $input.first().json;
const expectedSecret = $env.N8N_WEBHOOK_HMAC_SECRET;

for (const r of results) {
  if (r.status !== 'error') {
    try {
      await $http.request({
        method: 'POST',
        url:    'http://localhost:5678/webhook/cf-scene',
        body:   {
          secret:       expectedSecret,
          action:       'update_scene',
          content_id,
          scene_number: r.scene_number,
          asset_url:    r.result_url,
          provider:     r.provider,
          status:       'generated'
        },
        json: true
      });
    } catch (err) {
      // Log but continue — don't fail the whole workflow for a status update error
      console.error(`Failed to update scene ${r.scene_number}: ${err.message}`);
    }
  }
}

return [{ json: { content_id, content, results, scenes_dispatched } }];

// Sync to Kitsu: mark step 9 (Generate Assets) as done
const { content_id, content, results, scenes_dispatched } = $input.first().json;
const expectedSecret = $env.N8N_WEBHOOK_HMAC_SECRET;

try {
  await $http.request({
    method: 'POST',
    url:    'http://localhost:5678/webhook/cf-kitsu-sync',
    body:   {
      secret:     expectedSecret,
      action:     'update_task_status',
      content_id,
      step:       9,
      status:     'done'
    },
    json: true
  });
} catch (err) {
  // Non-fatal: Kitsu sync failure should not block the pipeline
  console.error(`Kitsu sync failed: ${err.message}`);
}

return [{ json: { content_id, results, scenes_dispatched } }];
